// Parse AI response and merge with original job data
const output = []

for (let i = 0; i < items.length; i++) {
  const job = items[i].json

  let aiResponse = {}

  const rawResponse = job.output || job.text || job.response || '{}'

  try {
    let cleaned = rawResponse.trim()
    const fence = String.fromCharCode(96, 96, 96)
    if (cleaned.startsWith(fence)) {
      const firstNewline = cleaned.indexOf('\n')
      if (firstNewline !== -1) {
        cleaned = cleaned.substring(firstNewline + 1)
      }
      if (cleaned.endsWith(fence)) {
        cleaned = cleaned.substring(0, cleaned.length - 3)
      }
      cleaned = cleaned.trim()
    }
    aiResponse = JSON.parse(cleaned)
  } catch(e) {
    aiResponse = {
      score: 5,
      fit: false,
      reasoning: 'AI response parsing failed - needs manual review: ' + rawResponse.substring(0, 200),
      recommended_resume_focus: '',
      category: 'MANUAL_REVIEW'
    }
  }

  output.push({
    json: {
      ...job,
      title: job.title || '',
      company: job.companyName || job.company || '',
      location: job.location || '',
      apply_url: job.applyUrl || job.apply_url || '',
      linkedin_url: job.link || job.linkedin_url || '',
      is_easy_apply: !job.applyUrl || job.applyUrl === '',
      resume_code: job.resume_code || '',
      title_code: job.title_code || '',
      location_code: job.location_code || '',
      normalized_title: job.normalized_title || '',
      normalized_location: job.normalized_location || '',
      descriptionText: job.descriptionText || '',
      seniorityLevel: job.seniorityLevel || '',
      employmentType: job.employmentType || '',
      ai_score: aiResponse.score || 0,
      ai_fit: aiResponse.fit || false,
      ai_reasoning: aiResponse.reasoning || '',
      ai_resume_focus: aiResponse.recommended_resume_focus || '',
      ai_category: aiResponse.category || 'UNKNOWN'
    }
  })
}

return output

// Log rejected jobs for reference
const fs = require('fs');

const output = [];

// Load existing queue
let queue = { filtered_jobs: [], apply_url_jobs: [], easy_apply_jobs: [], applied: [], rejected: [] };
try {
  queue = JSON.parse(fs.readFileSync('/data/job_queue.json', 'utf8'));
} catch(e) {}

for (const item of items) {
  const job = item.json;

  queue.rejected.push({
    title: job.title,
    company: job.company,
    location: job.location,
    ai_score: job.ai_score,
    ai_reasoning: job.ai_reasoning,
    ai_category: job.ai_category,
    rejected_at: new Date().toISOString()
  });

  output.push({
    json: {
      ...job,
      status: 'rejected',
      reason: job.ai_reasoning
    }
  });
}

try {
  fs.writeFileSync('/data/job_queue.json', JSON.stringify(queue, null, 2), 'utf8');
} catch(e) {}

return output;

// Store resume in index and prepare for sending
const fs = require('fs');

const output = [];

for (const item of items) {
  const job = item.json;

  // Load current index
  let index = [];
  try {
    const raw = fs.readFileSync('/metadata/resume_index.json', 'utf8');
    index = JSON.parse(raw);
    if (!Array.isArray(index)) index = [index];
  } catch(e) {
    index = [];
  }

  // Create record
  const record = {
    code: job.resume_code,
    title_code: job.title_code,
    location_code: job.location_code,
    job_title: job.title,
    location: job.location,
    company: job.company,
    ai_score: job.ai_score,
    ai_category: job.ai_category,
    is_easy_apply: job.is_easy_apply,
    apply_url: job.is_easy_apply ? job.linkedin_url : job.apply_url,
    timestamp: new Date().toISOString(),
    pdf: `generated/${job.resume_code}.pdf`,
    status: 'generated'
  };

  index.push(record);

  // Save index
  try {
    fs.writeFileSync('/metadata/resume_index.json', JSON.stringify(index, null, 2), 'utf8');
  } catch(e) {
    // If /metadata mount fails, try relative
    try {
      fs.writeFileSync('/data/../metadata/resume_index.json', JSON.stringify(index, null, 2), 'utf8');
    } catch(e2) {}
  }

  // Copy PDF to sent/ as Kaushik-Shahare.pdf
  try {
    const src = `/latex/generated/${job.resume_code}.pdf`;
    if (!fs.existsSync('/data/sent')) { fs.mkdirSync('/data/sent', { recursive: true }); }
    const dst = `/data/sent/Kaushik-Shahare.pdf`;
    const dstCopy = `/data/sent/${job.resume_code}.pdf`;
    if (fs.existsSync(src)) {
      fs.copyFileSync(src, dst);
      fs.copyFileSync(src, dstCopy);
      record.status = 'ready_to_send';
    }
  } catch(e) {}

  output.push({
    json: {
      ...job,
      resume_record: record,
      final_pdf: `sent/Kaushik-Shahare.pdf`,
      archived_pdf: `generated/${job.resume_code}.pdf`
    }
  });
}

return output;

// Categorize and queue jobs for application
const fs = require('fs');

const output = [];

// Load existing queue
let queue = { filtered_jobs: [], apply_url_jobs: [], easy_apply_jobs: [], applied: [], rejected: [] };
try {
  queue = JSON.parse(fs.readFileSync('/data/job_queue.json', 'utf8'));
} catch(e) {}

for (const item of items) {
  const job = item.json;

  const queueEntry = {
    resume_code: job.resume_code,
    title: job.title,
    company: job.company,
    location: job.location,
    ai_score: job.ai_score,
    ai_category: job.ai_category,
    is_easy_apply: job.is_easy_apply,
    apply_url: job.is_easy_apply ? job.linkedin_url : job.apply_url,
    resume_pdf: job.final_pdf || `generated/${job.resume_code}.pdf`,
    queued_at: new Date().toISOString(),
    status: 'queued'
  };

  queue.filtered_jobs.push(queueEntry);

  if (job.is_easy_apply) {
    queue.easy_apply_jobs.push(queueEntry);
  } else {
    queue.apply_url_jobs.push(queueEntry);
  }

  output.push({
    json: {
      ...job,
      queue_status: 'queued',
      application_type: job.is_easy_apply ? 'EASY_APPLY' : 'EXTERNAL_URL',
      application_url: queueEntry.apply_url
    }
  });
}

// Save queue
try {
  fs.writeFileSync('/data/job_queue.json', JSON.stringify(queue, null, 2), 'utf8');
} catch(e) {}

return output;

